hound.on(
  'report.daily',
  async (ctx) => {
    await generateDailyReport();
  },
  {
    repeat: { pattern: '0 6 * * *' }, // every day at 06:00
  }
);

await hound.emitAsync('report.generate', { userId: 'u_123' }, {
  id: `report-weekly-u_123`, // stable ID prevents duplicates on restart
  repeat: { pattern: '0 8 * * 1' }, // every Monday at 08:00
});
